const SUPABASE_URL = 'https://byoriebhtbysanjhimlu.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJ5b3JpZWJodGJ5c2FuamhpbWx1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NzcyNTY5NSwiZXhwIjoyMDgzMzAxNjk1fQ.0hMfqk1z6zO58xNlTLVdK7_JmLD6TrYiEUYJIuQAXSY';
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` };
const queueResp = await fetch(`${SUPABASE_URL}/rest/v1/social_content_queue?select=meeting_record_id&meeting_record_id=not.is.null`, { headers });
const queued = await queueResp.json();
const queuedIds = queued.map(r => r.meeting_record_id);
const sevenDaysAgo = new Date(Date.now() - 7*24*60*60*1000).toISOString();
const meetingsResp = await fetch(`${SUPABASE_URL}/rest/v1/meeting_records?select=*&created_at=gte.${sevenDaysAgo}&order=created_at.desc&limit=10`, { headers });
const meetings = await meetingsResp.json();
const unprocessed = meetings.filter(m => !queuedIds.includes(m.id));
if (unprocessed.length === 0) return [{ json: { _empty: true, message: 'No unprocessed meetings found' } }];
return unprocessed.map(m => ({ json: m }));

